/**
 * Preview Engine — Core playback logic for real-time video preview
 *
 * Pure functions + state machine for:
 * - Slide-based playback with per-scene durations
 * - Time ↔ scene mapping (global time → scene index + local time)
 * - Seek, speed control, looping
 * - Audio sync coordination (scene audioUrl + background music)
 *
 * @module preview-engine
 */

// ============================================================================
// TYPES
// ============================================================================

/** Minimal scene data needed by the preview engine */
export interface PreviewScene {
  id: string;
  duration: number;
  audioUrl?: string;
  musicConfig?: {
    url: string;
    volume: number; // 0–100
    fadeIn?: number;
    fadeOut?: number;
  };
}

/** Playback state */
export type PlaybackStatus = 'stopped' | 'playing' | 'paused';

/** Speed preset values */
export const SPEED_PRESETS = [0.25, 0.5, 0.75, 1, 1.25, 1.5, 2] as const;
export type SpeedPreset = (typeof SPEED_PRESETS)[number];

/** Full preview state */
export interface PreviewState {
  status: PlaybackStatus;
  currentTime: number;       // global time in seconds
  totalDuration: number;
  playbackSpeed: number;
  loop: boolean;
  currentSceneIndex: number;
  sceneLocalTime: number;    // time within current scene
  sceneProgress: number;     // 0–1 progress within current scene
}

/** Scene timing info (computed from scene list) */
export interface SceneTiming {
  sceneIndex: number;
  sceneId: string;
  startTime: number;
  endTime: number;
  duration: number;
}

/** Result of mapping a global time to a scene */
export interface TimeToSceneResult {
  sceneIndex: number;
  sceneId: string;
  sceneLocalTime: number;
  sceneProgress: number;
  sceneDuration: number;
  sceneStartTime: number;
}

// ============================================================================
// CONSTANTS
// ============================================================================

export const DEFAULT_SCENE_DURATION = 5;
export const MIN_SPEED = 0.25;
export const MAX_SPEED = 4;
export const DEFAULT_SPEED = 1;
export const FRAME_RATE = 60; // target FPS for rAF calculations

// ============================================================================
// PURE FUNCTIONS — Scene Timings
// ============================================================================

/**
 * Compute timing info for all scenes.
 * Each scene plays sequentially; start = cumulative sum of previous durations.
 */
export function computeSceneTimings(scenes: ReadonlyArray<PreviewScene>): SceneTiming[] {
  let cumulative = 0;
  return scenes.map((scene, index) => {
    const duration = Math.max(0, scene.duration || DEFAULT_SCENE_DURATION);
    const timing: SceneTiming = {
      sceneIndex: index,
      sceneId: scene.id,
      startTime: cumulative,
      endTime: cumulative + duration,
      duration,
    };
    cumulative += duration;
    return timing;
  });
}

/**
 * Get total duration of all scenes combined.
 */
export function getTotalDuration(scenes: ReadonlyArray<PreviewScene>): number {
  return scenes.reduce(
    (sum, scene) => sum + Math.max(0, scene.duration || DEFAULT_SCENE_DURATION),
    0,
  );
}

/**
 * Get the start time (global) of the scene at `sceneIndex`.
 */
export function getSceneStartTime(
  scenes: ReadonlyArray<PreviewScene>,
  sceneIndex: number,
): number {
  if (sceneIndex < 0 || sceneIndex >= scenes.length) return 0;
  let cumulative = 0;
  for (let i = 0; i < sceneIndex; i++) {
    cumulative += Math.max(0, scenes[i].duration || DEFAULT_SCENE_DURATION);
  }
  return cumulative;
}

// ============================================================================
// PURE FUNCTIONS — Time ↔ Scene Mapping
// ============================================================================

/**
 * Given a global time, find which scene is active and the local time within it.
 *
 * Edge cases:
 * - time < 0 → clamp to 0 (first scene, localTime 0)
 * - time ≥ totalDuration → last scene at end (progress 1)
 * - empty scenes → returns index -1
 */
export function mapTimeToScene(
  scenes: ReadonlyArray<PreviewScene>,
  globalTime: number,
): TimeToSceneResult {
  if (scenes.length === 0) {
    return {
      sceneIndex: -1,
      sceneId: '',
      sceneLocalTime: 0,
      sceneProgress: 0,
      sceneDuration: 0,
      sceneStartTime: 0,
    };
  }

  const total = getTotalDuration(scenes);
  const clampedTime = Math.max(0, Math.min(globalTime, total));

  let cumulative = 0;
  for (let i = 0; i < scenes.length; i++) {
    const duration = Math.max(0, scenes[i].duration || DEFAULT_SCENE_DURATION);
    if (clampedTime < cumulative + duration || i === scenes.length - 1) {
      const localTime = clampedTime - cumulative;
      return {
        sceneIndex: i,
        sceneId: scenes[i].id,
        sceneLocalTime: Math.min(localTime, duration),
        sceneProgress: duration > 0 ? Math.min(localTime / duration, 1) : 0,
        sceneDuration: duration,
        sceneStartTime: cumulative,
      };
    }
    cumulative += duration;
  }

  // Fallback (should never reach due to i === scenes.length - 1 guard)
  const lastIndex = scenes.length - 1;
  const lastDuration = Math.max(0, scenes[lastIndex].duration || DEFAULT_SCENE_DURATION);
  return {
    sceneIndex: lastIndex,
    sceneId: scenes[lastIndex].id,
    sceneLocalTime: lastDuration,
    sceneProgress: 1,
    sceneDuration: lastDuration,
    sceneStartTime: total - lastDuration,
  };
}

/**
 * Given a scene index, calculate the global time at the start of that scene.
 * Optionally add a local offset.
 */
export function sceneToGlobalTime(
  scenes: ReadonlyArray<PreviewScene>,
  sceneIndex: number,
  localOffset: number = 0,
): number {
  const startTime = getSceneStartTime(scenes, sceneIndex);
  const duration =
    sceneIndex >= 0 && sceneIndex < scenes.length
      ? Math.max(0, scenes[sceneIndex].duration || DEFAULT_SCENE_DURATION)
      : 0;
  return startTime + Math.max(0, Math.min(localOffset, duration));
}

// ============================================================================
// PURE FUNCTIONS — Playback State Transitions
// ============================================================================

/**
 * Create initial preview state from scenes.
 */
export function createInitialState(scenes: ReadonlyArray<PreviewScene>): PreviewState {
  const total = getTotalDuration(scenes);
  const mapped = mapTimeToScene(scenes, 0);
  return {
    status: 'stopped',
    currentTime: 0,
    totalDuration: total,
    playbackSpeed: DEFAULT_SPEED,
    loop: false,
    currentSceneIndex: mapped.sceneIndex,
    sceneLocalTime: 0,
    sceneProgress: 0,
  };
}

/**
 * Advance time by delta (in seconds), respecting speed and total duration.
 * Returns updated state. If at end and not looping, status → 'paused'.
 */
export function advanceTime(
  state: PreviewState,
  deltaSec: number,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  if (state.status !== 'playing') return state;

  const effectiveDelta = deltaSec * state.playbackSpeed;
  let newTime = state.currentTime + effectiveDelta;
  const totalDuration = getTotalDuration(scenes);

  let newStatus: PlaybackStatus = 'playing';

  if (newTime >= totalDuration) {
    if (state.loop) {
      newTime = newTime % totalDuration;
    } else {
      newTime = totalDuration;
      newStatus = 'paused';
    }
  }

  newTime = Math.max(0, newTime);

  const mapped = mapTimeToScene(scenes, newTime);

  return {
    ...state,
    status: newStatus,
    currentTime: newTime,
    totalDuration,
    currentSceneIndex: mapped.sceneIndex,
    sceneLocalTime: mapped.sceneLocalTime,
    sceneProgress: mapped.sceneProgress,
  };
}

/**
 * Seek to a specific global time.
 */
export function seekTo(
  state: PreviewState,
  time: number,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  const totalDuration = getTotalDuration(scenes);
  const clampedTime = Math.max(0, Math.min(time, totalDuration));
  const mapped = mapTimeToScene(scenes, clampedTime);

  return {
    ...state,
    currentTime: clampedTime,
    totalDuration,
    currentSceneIndex: mapped.sceneIndex,
    sceneLocalTime: mapped.sceneLocalTime,
    sceneProgress: mapped.sceneProgress,
  };
}

/**
 * Seek to a specific scene (start of that scene).
 */
export function seekToScene(
  state: PreviewState,
  sceneIndex: number,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  const clampedIndex = Math.max(0, Math.min(sceneIndex, scenes.length - 1));
  const globalTime = sceneToGlobalTime(scenes, clampedIndex, 0);
  return seekTo(state, globalTime, scenes);
}

/**
 * Toggle play/pause.
 */
export function togglePlayPause(state: PreviewState): PreviewState {
  if (state.status === 'playing') {
    return { ...state, status: 'paused' };
  }
  return { ...state, status: 'playing' };
}

/**
 * Start playback.
 */
export function play(state: PreviewState): PreviewState {
  return { ...state, status: 'playing' };
}

/**
 * Pause playback.
 */
export function pause(state: PreviewState): PreviewState {
  if (state.status === 'playing') {
    return { ...state, status: 'paused' };
  }
  return state;
}

/**
 * Stop playback (reset to beginning).
 */
export function stop(
  state: PreviewState,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  const mapped = mapTimeToScene(scenes, 0);
  return {
    ...state,
    status: 'stopped',
    currentTime: 0,
    currentSceneIndex: mapped.sceneIndex,
    sceneLocalTime: 0,
    sceneProgress: 0,
  };
}

/**
 * Set playback speed.
 */
export function setSpeed(state: PreviewState, speed: number): PreviewState {
  const clampedSpeed = Math.max(MIN_SPEED, Math.min(speed, MAX_SPEED));
  return { ...state, playbackSpeed: clampedSpeed };
}

/**
 * Toggle loop.
 */
export function toggleLoop(state: PreviewState): PreviewState {
  return { ...state, loop: !state.loop };
}

/**
 * Skip forward/backward by `seconds`.
 */
export function skip(
  state: PreviewState,
  seconds: number,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  return seekTo(state, state.currentTime + seconds, scenes);
}

/**
 * Jump to next scene.
 */
export function nextScene(
  state: PreviewState,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  if (scenes.length === 0) return state;
  const nextIndex = Math.min(state.currentSceneIndex + 1, scenes.length - 1);
  return seekToScene(state, nextIndex, scenes);
}

/**
 * Jump to previous scene.
 * If more than 2s into current scene, jump to start of current scene instead.
 */
export function previousScene(
  state: PreviewState,
  scenes: ReadonlyArray<PreviewScene>,
): PreviewState {
  if (scenes.length === 0) return state;
  if (state.sceneLocalTime > 2) {
    // Jump to start of current scene
    return seekToScene(state, state.currentSceneIndex, scenes);
  }
  const prevIndex = Math.max(state.currentSceneIndex - 1, 0);
  return seekToScene(state, prevIndex, scenes);
}

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Format time as "M:SS" or "M:SS.m" depending on precision.
 */
export function formatPreviewTime(seconds: number, showMs: boolean = false): string {
  const totalSec = Math.max(0, seconds);
  const m = Math.floor(totalSec / 60);
  const s = Math.floor(totalSec % 60);

  if (showMs) {
    const ms = Math.floor((totalSec % 1) * 10);
    return `${m}:${s.toString().padStart(2, '0')}.${ms}`;
  }
  return `${m}:${s.toString().padStart(2, '0')}`;
}

/**
 * Compute seek bar position (0–1) from global time.
 */
export function getSeekPosition(currentTime: number, totalDuration: number): number {
  if (totalDuration <= 0) return 0;
  return Math.max(0, Math.min(currentTime / totalDuration, 1));
}

/**
 * Convert a seek bar position (0–1) to global time.
 */
export function seekPositionToTime(position: number, totalDuration: number): number {
  return Math.max(0, Math.min(position, 1)) * totalDuration;
}

/**
 * Get scene markers for the seek bar — relative positions (0–1) where scenes start.
 */
export function getSceneMarkers(
  scenes: ReadonlyArray<PreviewScene>,
): Array<{ position: number; sceneIndex: number; sceneId: string }> {
  const total = getTotalDuration(scenes);
  if (total <= 0 || scenes.length <= 1) return [];

  const timings = computeSceneTimings(scenes);
  // Skip first scene (starts at 0)
  return timings.slice(1).map((t) => ({
    position: t.startTime / total,
    sceneIndex: t.sceneIndex,
    sceneId: t.sceneId,
  }));
}

/**
 * Get the nearest speed preset to a given value.
 */
export function getNearestSpeedPreset(speed: number): SpeedPreset {
  let nearest: number = SPEED_PRESETS[0];
  let minDiff = Math.abs(speed - nearest);

  for (const preset of SPEED_PRESETS) {
    const diff = Math.abs(speed - preset);
    if (diff < minDiff) {
      minDiff = diff;
      nearest = preset;
    }
  }

  return nearest as SpeedPreset;
}

/**
 * Check if speed is one of the presets.
 */
export function isSpeedPreset(speed: number): speed is SpeedPreset {
  return (SPEED_PRESETS as readonly number[]).includes(speed);
}

/**
 * Cycle to next speed preset (wraps around).
 */
export function cycleSpeedPreset(currentSpeed: number): SpeedPreset {
  const current = getNearestSpeedPreset(currentSpeed);
  const currentIndex = SPEED_PRESETS.indexOf(current);
  const nextIndex = (currentIndex + 1) % SPEED_PRESETS.length;
  return SPEED_PRESETS[nextIndex];
}
